interface Observer {
    void update(String event, Object data);
}

class EventManager {
    private final Map<String, List<Observer>> listeners = new HashMap<>();

    public void subscribe(String event, Observer listener) {
        listeners.computeIfAbsent(event, k -> new ArrayList<>()).add(listener);
    }

    public void unsubscribe(String event, Observer listener) {
        List<Observer> list = listeners.get(event);
        if (list != null) list.remove(listener);
    }

    public void notify(String event, Object data) {
        List<Observer> list = listeners.get(event);
        if (list != null) list.forEach(l -> l.update(event, data));
    }
}

